using System.ComponentModel;
using System.Text;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.Logging;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// --- Build the IChatClient via MEAI ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Tools ---
var notebook = new Notebook();
var webSearcher = new WebSearcher();
var tools = new AITool[]
{
    AIFunctionFactory.Create(webSearcher.SearchWeb),
    AIFunctionFactory.Create(notebook.SaveNote),
    AIFunctionFactory.Create(notebook.GetNotes),
};

// --- Agent ---
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research assistant. Your job is to research a topic thoroughly
        by searching the web multiple times with different queries, saving key
        findings as notes, and then producing a concise summary.

        Workflow:
        1. Break the topic into 2-3 search queries that cover different angles.
        2. For each query, call SearchWeb and review the results.
        3. Save the most important facts using SaveNote.
        4. After gathering enough information, call GetNotes to review your notes.
        5. Produce a final summary that synthesizes all your findings.

        Be factual and cite sources where possible.
        """,
    name: "ResearchAgent",
    description: "Researches a topic using web search and note-taking tools");

agent.ChatClient = new FunctionInvokingChatClient(agent.ChatClient, new() { MaximumIterationsPerRequest = 10 });

// --- Chat options ---
var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 2048,
    Tools = tools,
});

// --- Get topic from user ---
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

// --- Run the agent ---
var session = await agent.CreateSessionAsync();
var response = await agent.RunAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session,
    runOptions);

Console.WriteLine("═══════════════════════════════════════");
Console.WriteLine("           RESEARCH SUMMARY");
Console.WriteLine("═══════════════════════════════════════\n");
Console.WriteLine(response.Text);

if (response.Usage is { } usage)
{
    Console.WriteLine($"\n--- Token usage: input={usage.InputTokenCount}, output={usage.OutputTokenCount}, total={usage.TotalTokenCount} ---");
}

// ───────────────────────────────────────────────
// Tool implementations
// ───────────────────────────────────────────────

/// <summary>Provides web search capability using a simple HTTP scraper.</summary>
sealed class WebSearcher
{
    private readonly HttpClient _http = new()
    {
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0" },
            { "Accept", "text/html" },
        },
        Timeout = TimeSpan.FromSeconds(15),
    };

    [Description("Search the web for information. Returns a summary of search results for the given query.")]
    public async Task<string> SearchWeb(
        [Description("The search query string")] string query)
    {
        Console.WriteLine($"  🌐 Searching: \"{query}\"");
        try
        {
            // Use DuckDuckGo lite as a simple, key-free search endpoint
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://lite.duckduckgo.com/lite/?q={encoded}";
            var html = await _http.GetStringAsync(url);

            var results = ParseSearchResults(html);
            if (results.Count == 0)
                return $"No results found for: {query}";

            var sb = new StringBuilder();
            sb.AppendLine($"Search results for: {query}\n");
            foreach (var (title, snippet, link) in results.Take(5))
            {
                sb.AppendLine($"• {title}");
                if (!string.IsNullOrEmpty(link))
                    sb.AppendLine($"  URL: {link}");
                if (!string.IsNullOrEmpty(snippet))
                    sb.AppendLine($"  {snippet}");
                sb.AppendLine();
            }
            return sb.ToString();
        }
        catch (Exception ex)
        {
            return $"Search failed for '{query}': {ex.Message}";
        }
    }

    private static List<(string Title, string Snippet, string Link)> ParseSearchResults(string html)
    {
        var results = new List<(string, string, string)>();

        // Simple extraction from DuckDuckGo Lite HTML
        var lines = html.Split('\n');
        string currentTitle = "";
        string currentLink = "";

        foreach (var rawLine in lines)
        {
            var line = rawLine.Trim();

            // Extract links with result class
            if (line.Contains("class=\"result-link\"", StringComparison.OrdinalIgnoreCase)
                || (line.Contains("<a ", StringComparison.OrdinalIgnoreCase)
                    && line.Contains("href=\"http", StringComparison.OrdinalIgnoreCase)
                    && !line.Contains("duckduckgo", StringComparison.OrdinalIgnoreCase)))
            {
                var hrefStart = line.IndexOf("href=\"", StringComparison.OrdinalIgnoreCase);
                if (hrefStart >= 0)
                {
                    hrefStart += 6;
                    var hrefEnd = line.IndexOf('"', hrefStart);
                    if (hrefEnd > hrefStart)
                        currentLink = line[hrefStart..hrefEnd];
                }

                currentTitle = StripHtml(line);
                if (!string.IsNullOrWhiteSpace(currentTitle) && !string.IsNullOrWhiteSpace(currentLink))
                {
                    results.Add((currentTitle, "", currentLink));
                    currentTitle = "";
                    currentLink = "";
                }
            }
            // Extract snippet text from result-snippet class
            else if (line.Contains("class=\"result-snippet\"", StringComparison.OrdinalIgnoreCase))
            {
                var snippet = StripHtml(line);
                if (results.Count > 0 && !string.IsNullOrWhiteSpace(snippet))
                {
                    var last = results[^1];
                    results[^1] = (last.Title, snippet, last.Link);
                }
            }
        }
        return results;
    }

    private static string StripHtml(string html)
    {
        var sb = new StringBuilder();
        bool inTag = false;
        foreach (var ch in html)
        {
            if (ch == '<') { inTag = true; continue; }
            if (ch == '>') { inTag = false; continue; }
            if (!inTag) sb.Append(ch);
        }
        return System.Net.WebUtility.HtmlDecode(sb.ToString()).Trim();
    }
}

/// <summary>In-memory notebook for storing research findings.</summary>
sealed class Notebook
{
    private readonly List<(string Title, string Content)> _notes = [];

    [Description("Save a research note. Use this to store important findings from search results.")]
    public string SaveNote(
        [Description("A short title for this note")] string title,
        [Description("The detailed content of the note")] string content)
    {
        _notes.Add((title, content));
        Console.WriteLine($"  📝 Note saved: \"{title}\"");
        return $"Note #{_notes.Count} saved: {title}";
    }

    [Description("Retrieve all previously saved research notes.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been saved yet.";

        Console.WriteLine($"  📋 Retrieving {_notes.Count} note(s)");
        var sb = new StringBuilder();
        for (int i = 0; i < _notes.Count; i++)
        {
            sb.AppendLine($"[Note {i + 1}] {_notes[i].Title}");
            sb.AppendLine(_notes[i].Content);
            sb.AppendLine();
        }
        return sb.ToString();
    }
}

