97. /// <summary>Provides web search capability using a simple HTTP scraper.</summary>
98. sealed class WebSearcher
99. {
100.     private readonly HttpClient _http = new()
101.     {
102.         DefaultRequestHeaders =
103.         {
104.             { "User-Agent", "ResearchAgent/1.0" },
105.             { "Accept", "text/html" },
106.         },
107.         Timeout = TimeSpan.FromSeconds(15),
108.     };
109. 
110.     [Description("Search the web for information. Returns a summary of search results for the given query.")]
111.     public async Task<string> SearchWeb(
112.         [Description("The search query string")] string query)
113.     {
114.         Console.WriteLine($"  🌐 Searching: \"{query}\"");
115.         try
116.         {
117.             // Use DuckDuckGo lite as a simple, key-free search endpoint
118.             var encoded = Uri.EscapeDataString(query);
119.             var url = $"https://lite.duckduckgo.com/lite/?q={encoded}";
120.             var html = await _http.GetStringAsync(url);
121. 
122.             var results = ParseSearchResults(html);
123.             if (results.Count == 0)
124.                 return $"No results found for: {query}";
125. 
126.             var sb = new StringBuilder();
127.             sb.AppendLine($"Search results for: {query}\n");
128.             foreach (var result in results.Take(5))
129.             {
130.                 sb.AppendLine($"• {result.Title}");
131.                 if (!string.IsNullOrEmpty(result.Link))
132.                     sb.AppendLine($"  URL: {result.Link}");
133.                 if (!string.IsNullOrEmpty(result.Snippet))
134.                     sb.AppendLine($"  {result.Snippet}");
135.                 sb.AppendLine();
136.             }
137.             return sb.ToString();
138.         }
139.         catch (Exception ex)
140.         {
141.             return $"Search failed for '{query}': {ex.Message}";
142.         }
143.     }
144. 
145.     private static List<(string Title, string Snippet, string Link)> ParseSearchResults(string html)
146.     {
147.         var results = new List<(string Title, string Snippet, string Link)>();
148. 
149.         // Simple extraction from DuckDuckGo Lite HTML
150.         var lines = html.Split('\n');
151.         string currentTitle = "";
152.         string currentLink = "";
153. 
154.         foreach (var rawLine in lines)
155.         {
156.             var line = rawLine.Trim();
157. 
158.             // Extract links with result class
159.             if (line.Contains("class=\"result-link\"", StringComparison.OrdinalIgnoreCase)
160.                 || (line.Contains("<a ", StringComparison.OrdinalIgnoreCase)
161.                     && line.Contains("href=\"http", StringComparison.OrdinalIgnoreCase)
162.                     && !line.Contains("duckduckgo", StringComparison.OrdinalIgnoreCase)))
163.             {
164.                 var hrefStart = line.IndexOf("href=\"", StringComparison.OrdinalIgnoreCase);
165.                 if (hrefStart >= 0)
166.                 {
167.                     hrefStart += 6;
168.                     var hrefEnd = line.IndexOf('"', hrefStart);
169.                     if (hrefEnd > hrefStart)
170.                         currentLink = line[hrefStart..hrefEnd];
171.                 }
172. 
173.                 currentTitle = StripHtml(line);
174.                 if (!string.IsNullOrWhiteSpace(currentTitle) && !string.IsNullOrWhiteSpace(currentLink))
175.                 {
176.                     results.Add((currentTitle, "", currentLink));
177.                     currentTitle = "";
178.                     currentLink = "";
179.                 }
180.             }
181.             // Extract snippet text from result-snippet class
182.             else if (line.Contains("class=\"result-snippet\"", StringComparison.OrdinalIgnoreCase))
183.             {
184.                 var snippet = StripHtml(line);
185.                 if (results.Count > 0 && !string.IsNullOrWhiteSpace(snippet))
186.                 {
187.                     var last = results[^1];
188.                     results[^1] = (last.Title, snippet, last.Link);
189.                 }
190.             }
191.         }
192.         return results;
193.     }
194. 
195.     private static string StripHtml(string html)
196.     {
197.         var sb = new StringBuilder();
198.         bool inTag = false;
199.         foreach (var ch in html)
200.         {
201.             if (ch == '<') { inTag = true; continue; }
202.             if (ch == '>') { inTag = false; continue; }
203.             if (!inTag) sb.Append(ch);
204.         }
205.         return System.Net.WebUtility.HtmlDecode(sb.ToString()).Trim();
206.     }
207. }
